<template>
<div>
  <div class="py-5 sm:py-10">
    <img
      src="@/assets/svg/Logo.svg"
      alt="Maricel Fornaleza logo"
      class="mx-auto w-24 sm:w-36 lg:w-28 xl:w-36 cursor-pointer"
      loading="lazy"
      @click="goHome()"
    />
    <div
      class="
        mt-10
        w-full
        h-[400px]
        bg-black bg-cover bg-center bg-fixed
        lg:h-[600px]
      "
      :style="background(project.featured_img)"
    ></div>

    <div class="px-5 py-10 mx-auto lg:px-0 lg:w-8/12 lg:py-20 3xl:w-1/2">
      <project-details :project="project"></project-details>
      <project-team v-if="project.team" :team="project.team"> </project-team>
      <project-challenge v-if="project.challenges" :challenges="project.challenges"></project-challenge>
      <project-solution v-if="project.solution" :img="project.solution"></project-solution>
      <!-- <div
        class="mt-10 w-full h-[400px] bg-black bg-cover bg-center lg:h-[600px]"
        :style="background(project.featured_img)"
      ></div> -->
    </div>
  </div>
  <footer-section></footer-section>

</div>
  
</template>
<script>
import projects from "@/assets/data/projects.json";
import ProjectDetails from "@/components/partials/ProjectDetails.vue";
import FooterSection from "@/components/sections/FooterSection.vue";

import router from "@/router";
import ProjectTeam from '../components/partials/ProjectTeam.vue';
import ProjectChallenge from "@/components/partials/ProjectChallenge.vue"
import ProjectSolution from "@/components/partials/ProjectSolution.vue"


export default {
  data() {
    return {
      key: null,
      project: null,
      projects,
    };
  },
  components: {
    ProjectDetails,
    FooterSection,
    ProjectTeam,
    ProjectChallenge,
    ProjectSolution
    
  },
  created() {
    var param = this.$route.params.key;
    this.key = param;

    this.getProject();
  },
  methods: {
    getProject() {
      var project = projects.filter((projects) => projects.key.match(this.key));
      this.project = project[0];
    },
    background(src) {
      let bgImage = require("@/assets/projects/" + src);
      return {
        backgroundImage: `url("${bgImage}")`,
      };
    },
    goHome() {
      router.push("/");
    },
  },
};
</script>